const { target_host, target_type, services, session_id } = $('📥 Input').first().json;
if (!target_host) throw new Error('target_host erforderlich');
const cmd = `echo "=DISK=" && df -h && echo "=MEM=" && free -m && echo "=LOAD=" && uptime && echo "=SERVICES=" && systemctl list-units --state=failed --no-legend 2>/dev/null | head -20`;
return { target_host, target_type: target_type || 'lxc', command: cmd,
  services: services || [], session_id: session_id || require('crypto').randomUUID() };

const input = $('📥 Input').first().json;
const ssh = $('💻 SUB: SSH Execute').first().json;
const output = ssh?.data?.stdout || '(keine Daten)';
return { prompt: `Health-Check für ${input.target_host}:\n\n${output.substring(0,4000)}\n\nBewerte: Disk, Memory, Load, Services. Antworte als JSON: {health_score(0-100), status(healthy/warning/critical), issues:[{type,value,threshold,message}], recommendations:[]}`,
  model: 'claude-sonnet-4-6', max_tokens: 1000, session_id: input.session_id };

const input = $('📥 Input').first().json;
const claude = $('🤖 SUB: Claude').first().json;
const r = typeof claude.response === 'string' ? JSON.parse(claude.response) : claude.response || {};
return { exit_code: 'success', session_id: input.session_id,
  data: { target_host: input.target_host, health_score: r.health_score || 0,
    status: r.status || 'unknown', issues: r.issues || [], recommendations: r.recommendations || [] },
  timestamp: new Date().toISOString() };
